import{_ as e,c as a,S as l,o as s}from"./chunks/framework.BjmDYXuv.js";const g=JSON.parse('{"title":"Deployment","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"internal/deployment.md","filePath":"internal/deployment.md","lastUpdated":1776164417000}'),i={name:"internal/deployment.md"};function n(d,t,o,r,c,p){return s(),a("div",null,t[0]||(t[0]=[l(`<h1 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h1><p>The ColliderML backend can be deployed via Render (staging/production), Docker Compose (local development), or any platform that runs Docker containers.</p><h2 id="render" tabindex="-1">Render <a class="header-anchor" href="#render" aria-label="Permalink to &quot;Render&quot;">​</a></h2><p><code>backend/render.yaml</code> defines a Render Blueprint:</p><ul><li><strong>Branch:</strong> <code>staging</code> (auto-deploys on push)</li><li><strong>Plan:</strong> Starter</li><li><strong>Region:</strong> Oregon</li><li><strong>Health check:</strong> <code>GET /healthz</code></li></ul><h3 id="environment-variables-on-render" tabindex="-1">Environment variables on Render <a class="header-anchor" href="#environment-variables-on-render" aria-label="Permalink to &quot;Environment variables on Render&quot;">​</a></h3><p>Set these in the Render dashboard (or via <code>render.yaml</code> env groups):</p><table><thead><tr><th style="text-align:left;">Variable</th><th style="text-align:left;">Required</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><code>DATABASE_URL</code></td><td style="text-align:left;">Yes</td><td style="text-align:left;">Supabase connection string (Session mode, port 5432)</td></tr><tr><td style="text-align:left;"><code>ADMIN_TOKEN</code></td><td style="text-align:left;">Yes</td><td style="text-align:left;">Auto-generated by Render; share with admin Space operators</td></tr><tr><td style="text-align:left;"><code>SFAPI_CLIENT_ID</code></td><td style="text-align:left;">No</td><td style="text-align:left;">Leave empty for mock mode</td></tr><tr><td style="text-align:left;"><code>SFAPI_CLIENT_SECRET</code></td><td style="text-align:left;">No</td><td style="text-align:left;">PEM-encoded; leave empty for mock mode</td></tr><tr><td style="text-align:left;"><code>NERSC_PROJECT</code></td><td style="text-align:left;">No</td><td style="text-align:left;">e.g., <code>m4958</code></td></tr><tr><td style="text-align:left;"><code>NERSC_USER</code></td><td style="text-align:left;">No</td><td style="text-align:left;">NERSC service account</td></tr><tr><td style="text-align:left;"><code>CONTAINER_IMAGE</code></td><td style="text-align:left;">No</td><td style="text-align:left;">Default: <code>ghcr.io/opendatadetector/sw:0.2.2_...</code></td></tr><tr><td style="text-align:left;"><code>COLLIDERML_BRANCH</code></td><td style="text-align:left;">No</td><td style="text-align:left;">Default: <code>main</code>; set to <code>staging</code> for staging deploy</td></tr><tr><td style="text-align:left;"><code>HF_TOKEN</code></td><td style="text-align:left;">No</td><td style="text-align:left;">Needed for output upload to HuggingFace</td></tr><tr><td style="text-align:left;"><code>HF_DATASET_ORG</code></td><td style="text-align:left;">No</td><td style="text-align:left;">Default: <code>CERN</code></td></tr><tr><td style="text-align:left;"><code>GITHUB_WEBHOOK_SECRET</code></td><td style="text-align:left;">No</td><td style="text-align:left;">HMAC secret for PR-merged webhooks</td></tr><tr><td style="text-align:left;"><code>SMTP_*</code></td><td style="text-align:left;">No</td><td style="text-align:left;">See email section below</td></tr><tr><td style="text-align:left;"><code>POLL_INTERVAL_SECONDS</code></td><td style="text-align:left;">No</td><td style="text-align:left;">Default: <code>60</code></td></tr></tbody></table><h2 id="docker-compose-local-development" tabindex="-1">Docker Compose (local development) <a class="header-anchor" href="#docker-compose-local-development" aria-label="Permalink to &quot;Docker Compose (local development)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> colliderml-production/backend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example .env          # edit DATABASE_URL if using external Postgres</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose up -d           # starts postgres + backend</span></span></code></pre></div><p>Services:</p><ul><li><strong>postgres</strong> — PostgreSQL 16, migrations auto-applied on startup via <code>docker-entrypoint-initdb.d/</code></li><li><strong>backend</strong> — FastAPI app, depends on postgres healthcheck, exposed on port 8000</li></ul><p>The default <code>.env.example</code> uses mock SFAPI mode (credentials unset), so simulation submissions complete in ~2 s without NERSC access.</p><h2 id="database-migrations" tabindex="-1">Database migrations <a class="header-anchor" href="#database-migrations" aria-label="Permalink to &quot;Database migrations&quot;">​</a></h2><p>Migrations live in <code>backend/migrations/</code>:</p><table><thead><tr><th style="text-align:left;">File</th><th style="text-align:left;">Content</th></tr></thead><tbody><tr><td style="text-align:left;"><code>001_initial.sql</code></td><td style="text-align:left;">Core schema: users, credit_transactions, simulation_requests, global_config, monthly_usage view</td></tr><tr><td style="text-align:left;"><code>002_benchmarks.sql</code></td><td style="text-align:left;">Leaderboard tables: benchmark_submissions, benchmark_bests, benchmark_reproductions</td></tr><tr><td style="text-align:left;"><code>003_webhooks.sql</code></td><td style="text-align:left;">GitHub mapping: gh_hf_mapping</td></tr></tbody></table><p>Apply manually against Supabase (or any Postgres):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">psql</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DATABASE_URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend/migrations/001_initial.sql</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">psql</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DATABASE_URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend/migrations/002_benchmarks.sql</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">psql</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DATABASE_URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend/migrations/003_webhooks.sql</span></span></code></pre></div><p>Migrations are idempotent (use <code>CREATE TABLE IF NOT EXISTS</code> and <code>CREATE INDEX IF NOT EXISTS</code>). Safe to re-run.</p><h2 id="email-notifications" tabindex="-1">Email notifications <a class="header-anchor" href="#email-notifications" aria-label="Permalink to &quot;Email notifications&quot;">​</a></h2><p>Optional. Configure via:</p><table><thead><tr><th style="text-align:left;">Variable</th><th style="text-align:left;">Default</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>SMTP_HOST</code></td><td style="text-align:left;"><em>(empty)</em></td><td style="text-align:left;">SMTP server hostname</td></tr><tr><td style="text-align:left;"><code>SMTP_PORT</code></td><td style="text-align:left;"><code>587</code></td><td style="text-align:left;">SMTP port</td></tr><tr><td style="text-align:left;"><code>SMTP_USER</code></td><td style="text-align:left;"><em>(empty)</em></td><td style="text-align:left;">SMTP username</td></tr><tr><td style="text-align:left;"><code>SMTP_PASSWORD</code></td><td style="text-align:left;"><em>(empty)</em></td><td style="text-align:left;">SMTP password</td></tr><tr><td style="text-align:left;"><code>SMTP_FROM</code></td><td style="text-align:left;"><code>colliderml@noreply.example</code></td><td style="text-align:left;">Sender address</td></tr></tbody></table><p>If <code>SMTP_HOST</code> is unset, email is silently skipped. Errors are logged but never propagated (fire-and-forget).</p><p>Triggers: job completion sends a plain-text email with the request ID, channel, event count, and a <code>colliderml.load()</code> code snippet pointing at the output dataset.</p><h2 id="supabase-notes" tabindex="-1">Supabase notes <a class="header-anchor" href="#supabase-notes" aria-label="Permalink to &quot;Supabase notes&quot;">​</a></h2><ul><li>Use the <strong>Session mode</strong> connection string (port 5432), not the Transaction mode pooler (port 6543). <code>asyncpg</code> uses prepared statements which require session-level state.</li><li>The <code>monthly_usage</code> view uses <code>date_trunc(&#39;month&#39;, CURRENT_DATE)</code> so it resets automatically on the 1st of each month.</li></ul>`,26)]))}const y=e(i,[["render",n]]);export{g as __pageData,y as default};
